  auto f = [](T x) { return x; };

  // Optimization: Find the maximum key to reduce the number of sort passes.
  // This is a significant win if the actual key range is much smaller than
  // implied by the `bits` parameter (e.g., keys in [0, 255] but `bits` is 64).
  // The overhead is a single parallel reduction, which is much cheaper than
  // a full radix sort pass.
  if (!In.empty()) {
    // Find the maximum key value in parallel. parlay::reduce is highly optimized.
    auto max_key = parlay::reduce(In, parlay::maxm<T>());

    // Calculate the minimum number of bits required to distinguish all keys.
    // #bits = ceil(log2(max_key + 1)). parlay::log2_up(N) computes ceil(log2(N)).
    // If max_key is 0, all keys are 0, so 0 bits are needed for sorting.
    size_t actual_bits = (max_key == 0) ? 0 : parlay::log2_up(max_key + 1);

    // Use the smaller of the user-provided bits and the actual required bits.
    bits = std::min(bits, actual_bits);
  }

  // Call Parlay's highly optimized internal integer sort. It is a stable
  // parallel radix sort that is cache-efficient and handles skewed data well.
  return parlay::internal::integer_sort(parlay::make_slice(In), f, bits);
