// A high-performance, stable, parallel, least-significant-digit (LSD) first
// radix sort implementation.
//
// The algorithm works as follows:
// 1. It iterates through the bits of the integer keys, 8 bits at a time (a byte).
// 2. In each pass, it performs a stable sort on the current byte of the keys.
//    This stable sort is a parallel counting sort.
// 3. The parallel counting sort works in three stages:
//    a. Histogram: The input is divided into blocks. Each thread computes a local
//       histogram (256 counts) for its block. This is highly parallel.
//    b. Prefix Sum: The local histograms are transposed and scanned to compute
//       the starting position in the output array for each byte value from each block.
//    c. Permute: Each thread reads its input block again and, using the precomputed
//       offsets, moves each element to its final sorted position in an output buffer.
// 4. A double-buffering technique is used: the roles of the input and output
//    buffers are swapped after each pass to avoid memory allocations and copies.
// 5. The implementation is generic and works on any sequence of elements as long
//    as an extractor function `f` is provided to get an unsigned integer key.
// 6. For small inputs, it falls back to a parallel comparison-based sort
//    (parlay::stable_sort) to avoid the high overhead of radix sort.

template <typename In_S, typename F>
auto integer_sort(In_S&& s, F f, size_t bits) {
  using T = typename std::decay_t<In_S>::value_type;
  using K = std::invoke_result_t<F, T>;

  static_assert(std::is_unsigned_v<K>, "parlay::internal::integer_sort requires unsigned integer keys.");

  constexpr size_t kRadix = 8;
  constexpr size_t kHistSize = 1 << kRadix;

  size_t n = s.size();

  // For small inputs, a comparison-based sort is faster due to overheads.
  if (n < 2048) {
    return parlay::stable_sort(std::forward<In_S>(s), [&](const auto& a, const auto& b) {
      return f(a) < f(b);
    });
  }

  // Double-buffering strategy to avoid allocations in each pass
  auto tmp = parlay::sequence<T>::uninitialized(n);
  auto s_in = parlay::make_slice(s);
  auto s_out = parlay::make_slice(tmp);

  // Calculate the number of passes required for the given number of bits
  size_t num_passes = (bits == 0) ? 0 : (bits + kRadix - 1) / kRadix;

  for (size_t pass = 0; pass < num_passes; ++pass) {
    size_t shift = pass * kRadix;
    size_t current_radix_bits = std::min(kRadix, bits - shift);

    // Create a mask for the current chunk of bits
    K mask = (current_radix_bits >= std::numeric_limits<K>::digits)
                 ? std::numeric_limits<K>::max()
                 : (static_cast<K>(1) << current_radix_bits) - 1;

    // 1. Compute block-local histograms in parallel
    size_t block_size = (n + get_num_workers() * 4 - 1) / (get_num_workers() * 4);
    block_size = std::max<size_t>(block_size, 2048);
    size_t num_blocks = (n + block_size - 1) / block_size;

    auto histograms = parlay::sequence<parlay::sequence<size_t>>::from_function(num_blocks, [&](size_t i) {
      parlay::sequence<size_t> hist(kHistSize, 0);
      size_t start = i * block_size;
      size_t end = std::min(start + block_size, n);
      for (size_t j = start; j < end; ++j) {
        hist[(f(s_in[j]) >> shift) & mask]++;
      }
      return hist;
    });

    // 2. Compute global offsets for each bucket
    auto transposed_hists = parlay::transpose(histograms);

    auto bucket_offsets = parlay::sequence<parlay::sequence<size_t>>::from_function(kHistSize, [&](size_t i) {
        return parlay::scan_inclusive(transposed_hists[i]);
    });

    auto bucket_totals = parlay::sequence<size_t>::from_function(kHistSize, [&](size_t i) {
      return bucket_offsets[i].empty() ? 0 : bucket_offsets[i].back();
    });

    auto global_offsets = parlay::scan_inclusive(bucket_totals);

    // 3. Permute the data into the output buffer in parallel
    parlay::parallel_for(0, num_blocks, [&](size_t i) {
      size_t start = i * block_size;
      size_t end = std::min(start + block_size, n);

      auto local_offsets = parlay::sequence<size_t>::from_function(kHistSize, [&](size_t b) {
        size_t global_start = (b == 0) ? 0 : global_offsets[b - 1];
        size_t local_start = (i == 0) ? 0 : bucket_offsets[b][i - 1];
        return global_start + local_start;
      });

      for (size_t j = start; j < end; ++j) {
        size_t bucket = (f(s_in[j]) >> shift) & mask;
        s_out[local_offsets[bucket]++] = std::move(s_in[j]);
      }
    }, 1); // Granularity of 1 ensures one task per block

    // Swap buffers for the next pass
    std::swap(s_in, s_out);
  }

  // After the loop, the sorted data is in s_in.
  // If the number of passes is odd, the data is in the temporary buffer `tmp`.
  // If the number of passes is even, the data is back in the original buffer `s`.
  // The function must return a new sequence containing the sorted data.
  if (num_passes % 2 == 1) {
    // Data is in tmp, so we can return it directly.
    return tmp;
  } else {
    // Data is in the original slice s. We must copy it to a new sequence to return.
    return parlay::sequence<T>(s.begin(), s.end());
  }
}

