constexpr size_t kRadixBits = 8;
constexpr size_t kRadixSize = 1 << kRadixBits;
constexpr size_t kSeqThreshold = 4096;
constexpr size_t kTransposeBlockSize = 32;

// Sequential, stable count-sort pass for small inputs or the base case.
// It iterates backwards over the input when placing elements to ensure stability.
template <typename InIt, typename OutIt, typename KeyFn>
void seq_radix_sort_pass(InIt first, InIt last, OutIt out, KeyFn get_key) {
  size_t n = std::distance(first, last);
  if (n == 0) return;

  size_t counts[kRadixSize] = {0};
  for (auto it = first; it != last; ++it) {
    counts[get_key(*it)]++;
  }

  // Exclusive scan to find bucket starting positions
  size_t offset = 0;
  for (size_t i = 0; i < kRadixSize; i++) {
    size_t tmp = counts[i];
    counts[i] = offset;
    offset += tmp;
  }

  // Scatter elements to their new positions
  for (auto it = first; it != last; ++it) {
    out[counts[get_key(*it)]++] = std::move(*it);
  }
}

// Parallel, stable count-sort pass. This is the core of the radix sort.
// It uses a two-level counting scheme that is highly parallel and scalable.
template <typename InIt, typename OutIt, typename KeyFn>
void radix_sort_pass(parlay::slice<InIt, InIt> in, parlay::slice<OutIt, OutIt> out, KeyFn get_key) {
  size_t n = in.size();
  if (n <= kSeqThreshold) {
    seq_radix_sort_pass(in.begin(), in.end(), out.begin(), get_key);
    return;
  }

  // Oversubscribe to get more, smaller blocks, improving load balance.
  const size_t num_blocks = parlay::num_workers() * 4;
  const size_t block_size = (n + num_blocks - 1) / num_blocks;

  // 1. Compute local histograms for each block in parallel.
  auto hists = parlay::sequence<size_t>::uninitialized(num_blocks * kRadixSize);
  parlay::parallel_for(0, num_blocks, [&](size_t i) {
    auto local_hists = parlay::make_slice(hists.begin() + i * kRadixSize, hists.begin() + (i + 1) * kRadixSize);
    std::fill(local_hists.begin(), local_hists.end(), 0);
    size_t start = std::min(i * block_size, n);
    size_t end = std::min(start + block_size, n);
    for (size_t j = start; j < end; j++) {
      local_hists[get_key(in[j])]++;
    }
  }, 1);

  // 2. Transpose histograms for efficient prefix sums per bucket.
  // A blocked transpose is used to improve cache performance.
  auto T_hists = parlay::sequence<size_t>::uninitialized(kRadixSize * num_blocks);
  parlay::parallel_for(0, (num_blocks + kTransposeBlockSize - 1) / kTransposeBlockSize, [&](size_t p_b) {
    parlay::parallel_for(0, (kRadixSize + kTransposeBlockSize - 1) / kTransposeBlockSize, [&](size_t k_b) {
      size_t p_start = p_b * kTransposeBlockSize;
      size_t p_end = std::min((p_b + 1) * kTransposeBlockSize, num_blocks);
      size_t k_start = k_b * kTransposeBlockSize;
      size_t k_end = std::min((k_b + 1) * kTransposeBlockSize, kRadixSize);
      for (size_t p = p_start; p < p_end; p++) {
        for (size_t k = k_start; k < k_end; k++) {
          T_hists[k * num_blocks + p] = hists[p * kRadixSize + k];
        }
      }
    });
  });

  // 3. Compute inclusive prefix sums for each bucket across all blocks.
  parlay::parallel_for(0, kRadixSize, [&](size_t k) {
    auto row = parlay::make_slice(T_hists.begin() + k * num_blocks, T_hists.begin() + (k + 1) * num_blocks);
    parlay::scan_inclusive_inplace(row);
  }, 1);

  // 4. Compute global bucket starting positions via an exclusive scan.
  auto bucket_starts = parlay::sequence<size_t>::uninitialized(kRadixSize);
  parlay::parallel_for(0, kRadixSize, [&](size_t k) {
    bucket_starts[k] = T_hists[(k + 1) * num_blocks - 1]; // Total count for bucket k
  });
  parlay::scan_inplace(bucket_starts); // Exclusive scan for start positions

  // 5. Compute final write offsets for each block.
  // The original `hists` memory is reused to store these offsets.
  parlay::parallel_for(0, num_blocks, [&](size_t p) {
    auto my_offsets = parlay::make_slice(hists.begin() + p * kRadixSize, hists.begin() + (p + 1) * kRadixSize);
    for (size_t k = 0; k < kRadixSize; k++) {
      size_t local_offset = (p == 0) ? 0 : T_hists[k * num_blocks + p - 1];
      my_offsets[k] = bucket_starts[k] + local_offset;
    }
  });

  // 6. Scatter elements to their sorted positions. This is the move step.
  parlay::parallel_for(0, num_blocks, [&](size_t i) {
    size_t start = std::min(i * block_size, n);
    size_t end = std::min(start + block_size, n);
    auto my_offsets = parlay::make_slice(hists.begin() + i * kRadixSize, hists.begin() + (i + 1) * kRadixSize);
    for (size_t j = start; j < end; j++) {
      size_t k = get_key(in[j]);
      out[my_offsets[k]++] = std::move(in[j]);
    }
  }, 1);
}

} // namespace my_isort


template <class T>
auto int_sort(parlay::slice<T*,T*> In, size_t bits) {
  auto s = parlay::sequence<T>(In.begin(), In.end());
  auto tmp = parlay::sequence<T>::uninitialized(s.size());
  auto get_key = [](const T& x) { return x; };

  size_t n = s.size();
  if (n == 0) return parlay::sequence<T>();

  size_t num_passes = (bits == 0) ? 0 : (bits + my_isort::kRadixBits - 1) / my_isort::kRadixBits;

  auto* from = &s;
  auto* to = &tmp;

  for (size_t pass = 0; pass < num_passes; ++pass) {
    const size_t shift = pass * my_isort::kRadixBits;
    const auto mask = (1 << my_isort::kRadixBits) - 1;
    auto get_key_for_pass = [&](const T& x) {
      return (get_key(x) >> shift) & mask;
    };
    my_isort::radix_sort_pass(from->slice(), to->slice(), get_key_for_pass);
    std::swap(from, to);
  }

  // After the loops, `from` points to the sequence with the sorted data.
  // We return that sequence, relying on RVO to avoid a copy.
  if (from == &s) {
    return s;
  } else {
    return tmp;
  }
}

